#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=3e5+10,NN=6e5+10,BK=512,INF=0x3f3f3f3f;int n,Q,a[N],L,R; struct Nd{int l,r,cl,cr,lc,idx;}q[N];
int head[N],des[NN],nxt[NN],cgt,P[NN],ql[N],qr[N],top[N],fa[N],mxs[N],siz[N],dep[N],cdt;
int qL[N/BK+10],qR[N/BK+10],blk,loc[N],sz[N/BK+10],ans[N];bool vis[N];
inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
inline void Init(){rep(1,n,i)loc[i]=(i-1)/BK+1;blk=loc[n];rep(1,blk,i)qL[i]=qR[i-1]+1,qR[i]=i*BK;qR[blk]=n;}
inline void dfs1(const int &u=1,const int &f=0)
{
	dep[u]=dep[fa[u]=f]+1;siz[u]=1;int mx=0;
	grep(u,i)if(des[i]!=f){int v=des[i];dfs1(v,u);siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;}
}
inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
{
	P[ql[u]=++cdt]=a[u];top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
	grep(u,i)if(des[i]!=fa&&des[i]!=mxs[u])dfs2(des[i],u,des[i]);P[qr[u]=++cdt]=a[u];
}
inline int LCA(int u,int v){while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];return dep[u]<dep[v]?u:v;}
inline void ins(const int &v){vis[v]?--sz[loc[v]]:++sz[loc[v]];vis[v]^=1;}
inline int qry(const int &l,const int &r)
{
	int Bl=loc[l],Br=loc[r];if(Bl==Br){rep(l,r,i)if(vis[i])return i;return -1;}
	rep(l,qR[Bl],i)if(vis[i])return i;rep(qL[Br],r,i)if(vis[i])return i;
	for(int B=Bl+1;B<Br;++B)if(sz[B])rep(qL[B],qR[B],i)if(vis[i])return i; return -1;
}
int main()
{
	n=read();Q=read();rep(1,n,i)a[i]=read();rep(2,n,i)ins(read(),read());
	Init();dfs1();dfs2();rep(1,Q,i)
	{
		int u=read(),v=read();q[i].cl=read();q[i].cr=read();q[i].idx=i;if(ql[u]>ql[v]){int tmp(u);u=v;v=tmp;}
		if(ql[u]<=ql[v]&&qr[v]<=qr[u])q[i].l=ql[u],q[i].r=ql[v];else q[i].l=qr[u],q[i].r=ql[v],q[i].lc=LCA(u,v);
	}
	std::sort(q+1,q+Q+1,[&](const Nd&x,const Nd&y){return (x.l>>9)!=(y.l>>9)?((x.l>>9)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=L-1;rep(1,Q,i)
	{
		while(R<q[i].r)ins(P[++R]);while(L>q[i].l)ins(P[--L]); while(R>q[i].r)ins(P[R--]);while(L<q[i].l)ins(P[L++]);
		if(q[i].lc)ins(a[q[i].lc]);ans[q[i].idx]=qry(q[i].cl,q[i].cr);if(q[i].lc)ins(a[q[i].lc]);
		if(n==5539&&q[i].idx==622)puts("fuck you!");
	}
	rep(1,Q,i)if(ans[i]==0){printf("QwQ :: ans[%d] = 0\n",i);return 0;}
	rep(1,Q,i)printf("%d\n",ans[i]);return 0;
}
